/**
 * Simple in-process EventBus for publish/subscribe communication.
 *
 * This is a general-purpose utility EventBus with a subscribe/publish API,
 * used for dispatching notifications to channel handlers. It is distinct from
 * the domain-level EventBus in src/events/event-bus.ts which handles
 * application lifecycle events (order:created, user:updated, etc.).
 */

export type EventHandler<T = unknown> = (data: T) => void | Promise<void>;

export class SimpleEventBus {
  private subscribers: Map<string, EventHandler[]> = new Map();

  /**
   * Subscribe to an event by name. Returns an unsubscribe function.
   */
  subscribe<T = unknown>(event: string, handler: EventHandler<T>): () => void {
    const handlers = this.subscribers.get(event) ?? [];
    handlers.push(handler as EventHandler);
    this.subscribers.set(event, handlers);

    return () => {
      const current = this.subscribers.get(event) ?? [];
      const index = current.indexOf(handler as EventHandler);
      if (index >= 0) {
        current.splice(index, 1);
      }
    };
  }

  /**
   * Publish an event to all subscribers. Handlers are called in order.
   */
  async publish<T = unknown>(event: string, data: T): Promise<void> {
    const handlers = this.subscribers.get(event) ?? [];
    for (const handler of handlers) {
      await handler(data);
    }
  }

  /**
   * Get the number of subscribers for a given event.
   */
  subscriberCount(event: string): number {
    return this.subscribers.get(event)?.length ?? 0;
  }

  /**
   * Remove all subscribers.
   */
  clear(): void {
    this.subscribers.clear();
  }
}

